const tip=document.getElementById('tip'); const dash=document.getElementById('dash');
let locked=null, hideTimer=null, activePanel=null;
function hideTip(){ tip.classList.remove('show'); }
function clearFocus(){ dash.classList.remove('focusing'); dash.querySelectorAll('.panel').forEach(x=>x.classList.remove('hovered')); }
function wireTipCustomize(){
  const av=document.getElementById('ppAvTip');
  if(av) av.querySelectorAll('.pa').forEach(p=> p.onclick=(e)=>{ e.stopPropagation(); mgrAv=p.dataset.av; window.mgrAv=mgrAv; document.dispatchEvent(new CustomEvent('roster:change',{detail:{src:'mgr'}})); av.querySelectorAll('.pa').forEach(x=>x.classList.toggle('on',x===p)); const img=document.getElementById('mgrImg'); if(img) img.src=AV[mgrAv]; });
  const nm=document.getElementById('ppNameTip');
  if(nm){ nm.onclick=e=>e.stopPropagation(); nm.oninput=()=>{ mgrTyped=nm.value; mgrName=nm.value.trim()||"Tom Hobbes"; const o=document.getElementById('mgrNameOut'); if(o) o.textContent=mgrName; }; }
}
function cardHTML(info){
  const desc = Array.isArray(info.d) ? info.d.map(x=>`<p>${x}</p>`).join('') : `<p>${info.d}</p>`;
  let h=`<span class="tk">${info.k}</span><h4>${info.t}</h4>${desc}<ul>${info.p.map(x=>`<li>${CK}${x}</li>`).join('')}</ul>`;
  if(info.customize){
    h+=`<div class="tip-div"></div><div class="pp-label">Customize your Campaign Manager</div><div class="pp-avatars" id="ppAvTip">${MGR_HEADS.map(k=>`<div class="pa ${k===mgrAv?'on':''}" data-av="${k}"><img src="${AV[k]}"></div>`).join('')}</div><input class="pp-name" id="ppNameTip" placeholder="Name Your Campaign Manager:" value="${mgrTyped}" maxlength="22">`;
  }
  if(info.dvbtn){
    h+=`<div class="tip-div"></div><button class="deploy-switch" id="exploreDV"><span class="ds-rank">${RANK3}</span><span class="ds-tx"><b>Explore Deployment View</b></span><span class="ds-arrow">${GO}</span></button>`;
  }
  return h;
}
function showTip(panel,key){
  const info=INFO[key||panel.dataset.info]; if(!info) return;
  let html=cardHTML(info);
  if(info.also && INFO[info.also]){ html+=`<div class="tip-split"></div>`+cardHTML(INFO[info.also]); }
  tip.innerHTML=html;
  if(info.customize) wireTipCustomize();
  const ex=tip.querySelector('#exploreDV'); if(ex) ex.onclick=(e)=>{ e.stopPropagation(); location.hash='deployment-view'; };
  tip.classList.add('show');
  const r=panel.getBoundingClientRect(); const tw=tip.offsetWidth, th=tip.offsetHeight; const vw=innerWidth, vh=innerHeight, m=12;
  let left,top;
  if(r.right+m+tw<=vw){ left=r.right+m; top=r.top; }
  else if(r.left-m-tw>=0){ left=r.left-m-tw; top=r.top; }
  else if(r.bottom+m+th<=vh){ left=r.left; top=r.bottom+m; }
  else { left=r.left; top=r.top-m-th; }
  left=Math.max(m,Math.min(left,vw-tw-m)); top=Math.max(m,Math.min(top,vh-th-m));
  tip.style.left=left+'px'; tip.style.top=top+'px';
}
function openTip(p){ clearTimeout(hideTimer); if(activePanel!==p){ clearFocus(); dash.classList.add('focusing'); p.classList.add('hovered'); activePanel=p; showTip(p); } }
function scheduleHide(){ clearTimeout(hideTimer); hideTimer=setTimeout(()=>{ if(locked) return; clearFocus(); hideTip(); activePanel=null; },180); }
function wireTips(){
  dash.querySelectorAll('.panel').forEach(p=>{
    if(p.classList.contains('g-pn')) return;
    p.onmouseenter=()=>{ if(locked) return; openTip(p); };
    p.onmouseleave=()=>{ if(locked) return; scheduleHide(); };
    p.onclick=(e)=>{ if(e.target.closest('input,button,label,.pa,.sw,.mtoggle,.pin,.ph')) return;
      if(locked===p){ locked=null; clearFocus(); hideTip(); activePanel=null; }
      else { locked=p; clearTimeout(hideTimer); clearFocus(); dash.classList.add('focusing'); p.classList.add('hovered'); activePanel=p; showTip(p); } };
  });
}
tip.addEventListener('mouseenter',()=>{ if(locked) return; clearTimeout(hideTimer); });
tip.addEventListener('mouseleave',()=>{ if(locked) return; scheduleHide(); });
document.addEventListener('click',e=>{ if(locked && !e.target.closest('.panel') && !e.target.closest('.tip')){ locked=null; clearFocus(); hideTip(); activePanel=null; }});
window.addEventListener('scroll',()=>{ if(!locked){ clearTimeout(hideTimer); clearFocus(); hideTip(); activePanel=null; } });
window.addEventListener('resize',()=>{ if(locked||activePanel) showTip(locked||activePanel); });


