(function(){

(function(){
  function go(){
    requestAnimationFrame(function(){ var v=document.getElementById('v-wwsf'); (v||document.body).classList.add('ws-in'); });
    var els = document.querySelectorAll('.ws-reveal');
    if(!('IntersectionObserver' in window)){
      els.forEach(function(el){ el.classList.add('in'); }); return;
    }
    var io = new IntersectionObserver(function(entries){
      entries.forEach(function(e){
        if(e.isIntersecting){ e.target.classList.add('in'); io.unobserve(e.target); }
      });
    },{rootMargin:'0px 0px -8% 0px'});
    els.forEach(function(el){ io.observe(el); });
    var lb = document.getElementById('wsLightbox');
    var lbImg = lb.querySelector('img'), lbClose = lb.querySelector('.ws-lb-close'), lbLast = null;
    function lbOpen(src, alt){ lbImg.src = src; lbImg.alt = alt || ''; lb.hidden = false; document.body.classList.add('ws-noscroll'); lbLast = document.activeElement; lbClose.focus(); }
    function lbHide(){ lb.hidden = true; lbImg.src = ''; document.body.classList.remove('ws-noscroll'); if(lbLast && lbLast.focus) lbLast.focus(); }
    lbClose.addEventListener('click', lbHide);
    lb.addEventListener('click', function(e){ if(e.target === lb) lbHide(); });
    document.addEventListener('keydown', function(e){ if(e.key === 'Escape' && !lb.hidden) lbHide(); });
    document.querySelectorAll('.ws-pv img').forEach(function(im){
      im.setAttribute('tabindex', '0'); im.setAttribute('role', 'button');
      function open(){ lbOpen(im.src, im.alt); }
      im.addEventListener('click', open);
      im.addEventListener('keydown', function(e){ if(e.key === 'Enter' || e.key === ' '){ e.preventDefault(); open(); } });
    });
    document.querySelectorAll('.ws-tcard').forEach(function(c){
      function flip(){ var on = c.classList.toggle('open'); c.setAttribute('aria-expanded', on ? 'true' : 'false'); }
      c.addEventListener('click', flip);
      c.addEventListener('keydown', function(e){ if(e.key === 'Enter' || e.key === ' '){ e.preventDefault(); flip(); } });
    });
  }
  // in-app: run once the #v-wwsf view is active and laid out (not at load, where it is display:none)
  var _wwsfReady = false;
  function _wwsfBoot(){
    var v = document.getElementById('v-wwsf');
    if(_wwsfReady || !v || !v.classList.contains('active')) return;
    _wwsfReady = true; go();
  }
  window.addEventListener('resize', _wwsfBoot);   // the router dispatches resize when it shows a view
  window.addEventListener('hashchange', function(){ setTimeout(_wwsfBoot, 0); });
  if(document.readyState !== 'loading'){ _wwsfBoot(); } else { document.addEventListener('DOMContentLoaded', _wwsfBoot); }
})();

})();

